from math import isqrt
def A344514(n):
    c, j = 0, 1
    while (j2:=j**2) <= n:
        k = n//j2
        m = isqrt(n//k)
        c += (k**(m+1)-k**j)//(k-1) if k>1 else m-j+1
        j = m+1
    return c # _Chai Wah Wu_, May 17 2026

